// Ordena as mensagens pela data
items.sort((a, b) =>
  new Date(a.json.created_at).getTime() - new Date(b.json.created_at).getTime()
);

function formatarData(isoDate) {
  const d = new Date(isoDate);
  const dia = String(d.getDate()).padStart(2, "0");
  const mes = String(d.getMonth() + 1).padStart(2, "0");
  const ano = d.getFullYear();
  return `${dia}/${mes}/${ano}`;
}

const historico = [];

for (const item of items) {
  const row = item.json;
  const data = formatarData(row.created_at);

  if (row.mensagem_usuario?.trim()) {
    historico.push({
      autor: "Usuário",
      mensagem: row.mensagem_usuario.trim(),
      data
    });
  }

  if (row.mensagem_agente?.trim()) {
    historico.push({
      autor: "Agente",
      mensagem: row.mensagem_agente.trim(),
      data
    });
  }
}

// =====================================================
// NOVO TRECHO → Conta mensagens seguidas do agente
// =====================================================
let qtd_mensagens_sem_resposta = 0;

for (let i = historico.length - 1; i >= 0; i--) {
  if (historico[i].autor === "Agente") {
    qtd_mensagens_sem_resposta++;
  } else {
    break; // usuário falou → reset
  }
}
// =====================================================

return [
  {
    json: {
      historico_conversa: historico,
      qtd_mensagens_sem_resposta
    }
  }
];

return items.map(item => {
  let raw = item.json.output || "";
  let cleaned = raw;

  cleaned = cleaned.replace(/```json/gi, "");
  cleaned = cleaned.replace(/```/g, "");
  cleaned = cleaned.trim();

  let respostaIA = {};

  try {
    respostaIA = JSON.parse(cleaned);
  } catch (e) {
    respostaIA = {
      template: "erro",
      var_1: item.json.name || "",
      telefone: item.json.telefone || ""
    };
  }

  const templates = {
    mia_followup_1:
      "Oii {{1}}! Tudo bem? Vi que você ainda não respondeu. Fica à vontade, tá tudo tranquilo! Só queria saber se ficou alguma dúvida sobre como a M[IA] pode ajudar sua empresa. 😊",

    mia_followup_2:
      "Tudo bem, {{1}}? Tem um minutinho? 😄",

    mia_followup_3:
      "Opa {{1}}!!, sabia que empresas que implementam IA reduzem até 40% do tempo em tarefas operacionais? A M[IA] já fez isso acontecer para vários negócios. Faz sentido a gente conversar 30 minutinhos sobre isso?",

    mia_followup_4:
      "Oi {{1}}! Tenho um caso aqui que acho que vai te interessar. Um dos nossos clientes automatizou o atendimento e triplicou a capacidade de resposta sem contratar ninguém. Quer entender como funciona na prática?",

    mia_followup_5:
      "Olá {{1}}, estou organizando a agenda do nosso time para os próximos dias e queria reservar um horário exclusivo pra você antes de fechar. São só 30 minutos, as empresas que passaram por essa conversa saíram com um plano claro de como usar IA dentro delas. Ainda faz sentido pra você?",

    mia_followup_6:
      "Fala {{1}}, me desculpa insistir, mas não quero que você perca essa janela! Muitas empresas já estão usando IA pra sair na frente. Posso te mostrar como em 30 minutos. Topa?",

    mia_followup_7:
      "Tudo certo, {{1}}? Conseguimos um tempinho para trocar uma ideia rápida sobre IA em sua empresa? É coisa rápida. 😊",

    mia_despedida_encerramento:
      "Oi {{1}}! Por aqui é a Mia, da M[IA]. Como não tive seu retorno, vou encerrar nossa conversa por agora. Se quiser explorar como IA pode transformar sua empresa no futuro, é só me chamar. 😊"
  };

  const templateName = respostaIA.template;
  const textoTemplate = templates[templateName] || "Template não encontrado.";

  const mensagemFinal = textoTemplate
    .replace("{{1}}", respostaIA.var_1 || "");

  return {
    json: {
      ...respostaIA,
      mensagem_template: mensagemFinal
    }
  };
});

const entrada = $items("Estruturação do JSON de saída")[0].json;

if (!entrada.template || entrada.template === "pausar" || entrada.template === "erro") {
  return [{ json: { erro: `Template inválido ou pausado: ${entrada.template}` } }];
}

if (!entrada.telefone) {
  return [{ json: { erro: "Telefone não informado" } }];
}

const templateVarsCount = {
  mia_followup_1: 1,
  mia_followup_2: 1,
  mia_followup_3: 1,
  mia_followup_4: 1,
  mia_followup_5: 1,
  mia_followup_6: 1,
  mia_followup_7: 1,
  mia_despedida_encerramento: 1
};

const qtd = templateVarsCount[entrada.template] || 0;
const parametros = [];

if (qtd >= 1 && entrada.var_1) {
  parametros.push({ type: "text", text: String(entrada.var_1) });
}

const body = {
  messaging_product: "whatsapp",
  to: String(entrada.telefone),
  type: "template",
  template: {
    name: entrada.template,
    language: { code: "pt_BR" },
    components: parametros.length > 0
      ? [{ type: "body", parameters: parametros }]
      : []
  }
};

return [{ json: { resultado: body } }];

const lead = $input.first().json;

let telefone = lead.whatsapp || lead.phone || "";

// Remove tudo que não é número
telefone = telefone.replace(/\D/g, "");

// Se começar com 0, remove
if (telefone.startsWith("0")) {
  telefone = telefone.slice(1);
}

// Se tiver 10 dígitos (sem o 9), adiciona o 9 após o DDD
if (telefone.length === 10) {
  telefone = telefone.slice(0, 2) + "9" + telefone.slice(2);
}

// Adiciona DDI 55 se não tiver
if (telefone.length === 11) {
  telefone = "55" + telefone;
}

return [{
  json: {
    ...lead,
    telefone_normalizado: telefone
  }
}];

const template = `{
  "template": "mia_despedida_encerramento",
  "var_1": "${$json.name}",
  "telefone": "${$json.telefone}"
}`;

return [
  {
    json: {
      output: template
    }
  }
];

